  `year` int DEFAULT NULL,
  `question_number` varchar(20) DEFAULT NULL,
  `question_text` longtext NOT NULL,
  `question_latex` longtext,
  `solution_text` longtext NOT NULL,
  `solution_latex` longtext,
  `final_answer` text,
  `tags` json DEFAULT NULL,
  `question_type` varchar(50) DEFAULT NULL,
  `confidence_score` float DEFAULT NULL,
  `is_verified` tinyint(1) DEFAULT '0',
  `latex_valid` tinyint(1) DEFAULT '1',
  `generated_by` varchar(100) DEFAULT NULL,
  `diagram_path` varchar(500) DEFAULT NULL,
  `marks` int DEFAULT NULL,
  `difficulty` enum('easy','medium','hard') DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uniq_uid` (`question_uid`)
) ENGINE=InnoDB AUTO_INCREMENT=702 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
